while ($ELAPSED -lt $TIMEOUT) {
    # Check for action_required runs
    $ACTION_REQUIRED = gh run list -R $REPO --branch $BRANCH --status action_required --json databaseId,name,status --jq '.[].databaseId' 2>$null

    # Also check for any runs at all
    $ALL_RUNS = gh run list -R $REPO --branch $BRANCH --json databaseId,name,status,conclusion --jq '.[] | "\(.databaseId) \(.name) \(.status) \(.conclusion)"' 2>$null

    if ($ACTION_REQUIRED) {
        Write-Host "[$ELAPSED s] Found action_required runs: $ACTION_REQUIRED"
        break
    }

    if ($ALL_RUNS) {
        Write-Host "[$ELAPSED s] Runs found (not action_required yet):"
        Write-Host $ALL_RUNS

        # Check if runs are in progress or completed
        $IN_PROGRESS = gh run list -R $REPO --branch $BRANCH --status in_progress --json databaseId --jq '.[].databaseId' 2>$null
        $COMPLETED = gh run list -R $REPO --branch $BRANCH --status completed --json databaseId --jq '.[].databaseId' 2>$null

        if ($COMPLETED -and -not $IN_PROGRESS) {
            Write-Host "[$ELAPSED s] Runs are completed already!"
            break
        }
        if ($IN_PROGRESS) {
            Write-Host "[$ELAPSED s] Runs in progress, waiting..."
        }
    } else {
        Write-Host "[$ELAPSED s] No runs yet, waiting..."
    }

    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

